Def:
If('$(vSource)' = 'Schools First FCU',
  // Expression IF TRUE (uses Processing Date)
  Sum({<[Submitted To Processing Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} [Loan Amount] * [Interest Rate]) / 
  Sum({<[Submitted To Processing Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} [Loan Amount]),

  // Expression IF FALSE (uses Underwriting Date)
  Sum({<[Submitted To Underwriting Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} [Loan Amount] * [Interest Rate]) / 
  Sum({<[Submitted To Underwriting Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} [Loan Amount])
)

DefExpanded:
If('' = 'Schools First FCU',
  // Expression IF TRUE (uses Processing Date)
  Sum({<[Submitted To Processing Date] = {">=-<=-"}>} [Loan Amount] * [Interest Rate]) / 
  Sum({<[Submitted To Processing Date] = {">=-<=-"}>} [Loan Amount]),

