=Pick(Match(PerformanceGroup,'Pull Through','Turn Time'),
	Num(
	Count({<DateType*={'Application'},Date*={">=$(=Date(vCurrentDateAsDate-180))<=$(vCurrentDateAsDate)"},[Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}>}[Loan Number])
	/Count({<DateType*={'Application'},Date*={">=$(=Date(vCurrentDateAsDate-180))<=$(vCurrentDateAsDate)"},[Active Loan Flag]*={No}>}[Loan Number])
	,'#,##0.0%'),

