  // Expression to use IF TRUE
  Count({<[Submitted To Processing Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} distinct [Loan Number]),

  // Expression to use IF FALSE
  Count({<[Submitted To Underwriting Date] = {">=$(=MonthStart(vCurrentDateAsDate))<=$(=MonthEnd(vCurrentDateAsDate))"}>} distinct [Loan Number])
)

