//	Count({<DateType*={'Application'},Date*={">=$(=Date(vCurrentDateAsDate-180))<=$(vCurrentDateAsDate)"},[Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}>}[Loan Number])
//	/Count({<DateType*={'Application'},Date*={">=$(=Date(vCurrentDateAsDate-180))<=$(vCurrentDateAsDate)"},[Active Loan Flag]*={No}>}[Loan Number])
//	,'#,##0.0%'),
//	
//	Ceil(Avg({<[App-Close]*={">0"}, DateType*={'Funding'}, Date*={">=$(=Date(vCurrentDateAsDate-180))<=$(vCurrentDateAsDate)"}>}[App-Close]))
//	
//)

=Pick(Match(PerformanceGroup,'Pull Through','Turn Time'),
	Num(
	Count({<DateType*={'Application'},Date*={">=-<="},[Active Loan Flag]*={No}, [Pull Through Originated Flag]*={Yes}>}[Loan Number])
	/Count({<DateType*={'Application'},Date*={">=-<="},[Active Loan Flag]*={No}>}[Loan Number])
	,'#,##0.0%'),

    Round(Avg({<[App-Close]*={">0"}, DateType*={'Funding'}, Date*={">=-<="}>}[App-Close]),.01)

)

