Def:
= 'Displays data for last 12 months: ' & min({<[Date Interval]={"Last 12 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 12 Months"}>} Date)
   & 
  ' and last ' &
  Pick(
    Match($(vSalesScorecardMonthRange2), 3, 6),
    '3 months: ' & min({<[Date Interval]={"Last 3 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 3 Months"}>} Date),
    '6 months: ' & min({<[Date Interval]={"Last 6 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 6 Months"}>} Date)
  ) & 
  ' (Short Term)'

// Legacy expression
//'Displays data for rolling '&Pick(Match($(vOpsScorecardMonthRange),12,3),'13 months: '& min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date),'4 months: '& min({<Rolling4MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling4MonthFlag={Yes}>}Date))

//Legacy
//'Displays data for rolling 13 months: ' & min({<Rolling13MonthFlag={Yes}>}Date) & ' to ' & max({<Rolling13MonthFlag={Yes}>}Date)

