= 'Displays data for last 12 months: ' & min({<[Date Interval]={"Last 12 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 12 Months"}>} Date)
   & 
  ' and last ' &
  Pick(
    Match(3, 3, 6),
    '3 months: ' & min({<[Date Interval]={"Last 3 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 3 Months"}>} Date),
    '6 months: ' & min({<[Date Interval]={"Last 6 Months"}>} Date) & ' to ' & max({<[Date Interval]={"Last 6 Months"}>} Date)
  ) & 
  ' (Short Term)'

// Legacy expression
