Def:
=if(WildMatch(vChannel,'*Retail','Brok*')>=1,

if(GetSelectedCount([Loan Officer])=0 AND GetSelectedCount(Branch)=0, '-',
RangeAvg(
//Application Volume Quartile
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.25), 1,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.50), 2,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Application}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.75), 3,
4))),

//Closed Volume Quartile
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.25), 1,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.50), 2,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Closing}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.75), 3,
4))),

//Funded Volume Quartile
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.25), 1,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.50), 2,
if(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}>}[Loan Amount]) <= fractile({1}TOTAL aggr(sum({<Rolling13MonthFlag*={Yes}, DateType*={Funding}, [Loan Officer]*=>}[Loan Amount]),YearMonth,[Loan Officer]),.75), 3,
4))),

//Margin Quartile
if(Avg({<Rolling13MonthFlag*={Yes}, DateType*={Funding}>}[Margin (BPS)]) <=
