Def:
// Assuming Column(1) is the main static measure that defines the rows
If(Column(1) <> 0,

  // Check if at least one item is selected
  If(GetSelectedCount(FilterSelection) >= 1,
      Round(

      	IF(
        	Len(Only({<ColumnId = {$(=SubField(Concat(DISTINCT ColumnId, ', '), ', ', 1))}>} TotalMeasureType))=0,

              //Part 1: Get the Aggregation Type (Sum, Avg) using the 1st selected ColumnId
              $(=Only({<ColumnId = {$(=SubField(Concat(DISTINCT ColumnId, ', '), ', ', 1))}>} MeasureType))

              // Part 2: The Set Analysis and the Field to Aggregate
              ({<$(vPricingDashboardSet)>}

              // Get the ColumnName using the same 1st selected ColumnId
              [$(=Only({<ColumnId = {$(=SubField(Concat(DISTINCT ColumnId, ', '), ', ', 1))}>} ColumnName))]),

      		//If TotalMeasureType not empty
      		AVG(AGGR(

              // Part 1: Get the Aggregation Type (Sum, Avg) using the 1st selected ColumnId
              $(=Only({<ColumnId = {$(=SubField(Concat(DISTINCT ColumnId, ', '), ', ', 1))}>} MeasureType))

              // Part 2: The Set Analysis and the Field to Aggregate
              ({<$(vPricingDashboardSet)>}

              // Get the ColumnName using the same 1st selected ColumnId
              [$(=Only({<ColumnId = {$(=SubField(Concat(DISTINCT ColumnId, ', '), ', ', 1))}>} ColumnName))])

          	//Aggrigator
          	,[$(vScorecardActor)]))
            //,[Loan Number]))

          )

      ,.01)
  )
)

